Here's a complete example:

**XAML:**
```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

**ViewModel:**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = [];

    [ObservableProperty]
    private Item? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null; // reset so the same item can be re-selected
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` (bool) | Must be set to `false` when refresh completes, or the spinner never stops |
| `Command` | `RefreshCommand` | Triggered on pull-down gesture |
| `ItemsSource` | `Items` | Use `ObservableCollection<T>` for automatic UI updates |
| `SelectedItem` | `SelectedItem` | Two-way by default — set it to `null` after navigation so the row deselects |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires when selection changes; use instead of an event handler |

**Things to watch out for:**
- **Always set `IsRefreshing = false`** in a `finally` block — if your API throws, the spinner will stick otherwise.
- **Null out `SelectedItem`** after navigating; without this, tapping the same row a second time won't fire the command (the value hasn't "changed").
- `SelectionMode="Single"` is required — the default is `None`, which disables selection entirely.
